class Solution {
public:
    int isPrefixOfWord(string sentence, string searchWord) {
        int index = 1;
        stringstream ss(sentence);
        string word;
        while (ss >> word) {
            if (word.find(searchWord) == 0) {
                return index;
            }
            index++;
        }
        return -1;
    }
};
```
